import {
  Component,
  Input,
  Output,
  EventEmitter,
  ChangeDetectionStrategy,
} from '@angular/core';
import { CommonModule } from '@angular/common';

// ─── Data interfaces ──────────────────────────────────────────────────────────

export interface PatientVitals {
  wt: string;
  bmi: string;
  bp: string;
  temp: string;
  pulse: string;
}

export interface PatientInfoCard {
  wt: string;
  apptLast: string;
  pcp: string;
  language: string;
  translator: string;
}

export interface BillingCard {
  ins: string;
  accBal: string;
  guar: string;
  grBal: string;
  ref: string;
  ren: string;
}

export interface ButtonBarTab {
  /** Tab label text. */
  label: string;
  /** When true, renders a chevron-down caret after the label. */
  hasDropdown?: boolean;
}

// ─── Component ────────────────────────────────────────────────────────────────

/**
 * Patient Info banner — the full-width header panel displayed above the patient
 * chart. Provides a consolidated view of demographics, contact details, alerts,
 * label/value cards, and a configurable button bar.
 *
 * Layout (left → right):
 * - **Avatar** — 100 × 100 px placeholder image
 * - **Patient Details** — name + age, action buttons, contact row, alert labels
 * - **Label/Value Cards** — Patient Info · Billing Details · Notes · Secure Notes
 *   (each can be independently hidden)
 *
 * Below the main row: a **Button Bar** showing tab navigation (Medical Summary,
 * CDSS, Rx, Labs, etc.)
 */
@Component({
  selector: 'ds-patient-info',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './patient-info.component.html',
  styleUrl: './patient-info.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class PatientInfoComponent {
  // ─── Patient identity ─────────────────────────────────────────────────────

  /** Patient full name in LAST, First format. */
  @Input() patientName = 'RUSSELL, Kyle';
  /** Age and gender string. */
  @Input() ageGender = '40 yrs, M';
  /** Street address. */
  @Input() address = 'Street No & Name, City, Apartment Name, City, State, Zip';
  /** Date of birth (MM/DD/YYYY). */
  @Input() dob = '09/18/1983';
  /** Home / work phone. */
  @Input() phone = '(555) 865 5309';
  /** Mobile phone. */
  @Input() mobile = '(555) 865 5309';
  /** Email address. */
  @Input() email = 'krussell@email.com';

  // ─── Meta fields ──────────────────────────────────────────────────────────

  @Input() showAccountNo = true;
  @Input() accountNo = '10373';

  @Input() showMessengerEnabled = true;
  /** Whether the patient has Messenger enabled. */
  @Input() messengerEnabled = true;

  @Input() showWebEnabled = true;
  /** Whether the patient has web portal access. */
  @Input() webEnabled = true;

  // ─── Action buttons ───────────────────────────────────────────────────────

  @Input() showInfoButton = true;
  @Input() showHubButton = true;
  @Input() showAskEva = true;
  /** Show the SOGI rainbow badge. */
  @Input() showSogi = true;
  /** Show the healow Connect pill button. */
  @Input() showHealowConnect = true;

  // ─── Alert labels ─────────────────────────────────────────────────────────

  @Input() showAllergyAlert = true;
  @Input() showAllergies = true;
  @Input() showBillingAlert = true;
  @Input() showClinicalAlert = true;

  // ─── Label / value cards ─────────────────────────────────────────────────

  @Input() showPatientCard = true;
  @Input() patientCardData: PatientInfoCard = {
    wt: '284 lbs | 140 kg',
    apptLast: '03/19/02 (MJ)',
    pcp: 'JONES',
    language: 'English',
    translator: 'No',
  };

  @Input() showBillingCard = true;
  @Input() billingCardData: BillingCard = {
    ins: 'Self Pay',
    accBal: '$125.00',
    guar: 'Sameer',
    grBal: '$448.00',
    ref: 'SUCHON',
    ren: 'Willis, Sam',
  };

  @Input() showNotesCard = true;
  @Input() notesText =
    '1. This is a test sticky note.\nLAST VISIT: The Patient attended a concert and consumed a burrito, which led to food poisoning.';

  @Input() showSecureNotesCard = true;
  @Input() secureNotesText = '2. This is a secure test note.';

  // ─── Button bar ───────────────────────────────────────────────────────────

  @Input() showButtonBar = true;
  @Input() buttonBarTabs: ButtonBarTab[] = [
    { label: 'Medical Summary', hasDropdown: true },
    { label: 'CDSS' },
    { label: 'Rx' },
    { label: 'Labs' },
    { label: 'DI' },
    { label: 'Procedures' },
    { label: 'Growth Chart' },
    { label: 'Imm' },
    { label: 'T. Inj' },
    { label: 'Encounters' },
    { label: 'Patient Docs' },
    { label: 'Flowsheets', hasDropdown: true },
    { label: 'Notes' },
    { label: 'ASC', hasDropdown: true },
  ];

  // ─── Events ───────────────────────────────────────────────────────────────

  @Output() infoClick = new EventEmitter<void>();
  @Output() hubClick = new EventEmitter<void>();
  @Output() askEvaClick = new EventEmitter<void>();
  @Output() tabClick = new EventEmitter<ButtonBarTab>();
}

import {
  Component,
  Input,
  Output,
  EventEmitter,
  ChangeDetectionStrategy,
} from '@angular/core';
import { CommonModule } from '@angular/common';

export type BreadcrumbType = 'breadcrumb' | 'navigation';
export type BreadcrumbLevel = 1 | 2 | 3 | 4;

/** A single item in the breadcrumb/navigation trail. */
export interface BreadcrumbItem {
  /** Displayed label for this node. */
  label: string;
  /** Optional route or URL (used for `href` on breadcrumb links). */
  href?: string;
}

/**
 * Breadcrumb & Navigation component.
 *
 * - **breadcrumb**: all ancestor nodes are clickable links with an underline;
 *   used when users can jump back to any previous screen.
 * - **navigation**: plain text trail with no links/underline;
 *   used for orientation-only context where back-navigation isn't supported.
 *
 * When there are more than 3 ancestors the component collapses them behind a
 * "⋯" overflow button that expands to reveal the hidden nodes.
 */
@Component({
  selector: 'ds-breadcrumb',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './breadcrumb.component.html',
  styleUrl: './breadcrumb.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class BreadcrumbComponent {
  /**
   * Ordered list of nodes from root → current page.
   * The **last** item is always treated as the active (non-clickable) page.
   */
  @Input() items: BreadcrumbItem[] = [];

  /**
   * `breadcrumb` — ancestor nodes are clickable links (underlined).
   * `navigation` — all nodes are plain text; no interaction.
   */
  @Input() type: BreadcrumbType = 'breadcrumb';

  /** Emits the clicked item index when a breadcrumb ancestor is clicked. */
  @Output() itemClick = new EventEmitter<{ item: BreadcrumbItem; index: number }>();

  /** Controls whether the overflow popover is open. */
  overflowOpen = false;

  /** Chevron SVG path — shared across all separators. */
  readonly CHEVRON = `M5.5 4l3.5 4-3.5 4`;

  /** Ellipsis icon path — shown when nodes are collapsed. */
  readonly ELLIPSIS = `M4 8a1 1 0 1 1 2 0A1 1 0 0 1 4 8zm4 0a1 1 0 1 1 2 0A1 1 0 0 1 8 8zm4 0a1 1 0 1 1 2 0A1 1 0 0 1 12 8`;

  /** Returns true when there are more than 3 ancestor nodes (Level 4+). */
  get isOverflow(): boolean {
    return this.items.length > 3;
  }

  /** Ancestor nodes — everything except the last (current) item. */
  get ancestors(): BreadcrumbItem[] {
    return this.items.slice(0, -1);
  }

  /** The current / active page item. */
  get current(): BreadcrumbItem | null {
    return this.items.length > 0 ? this.items[this.items.length - 1] : null;
  }

  /** For overflow mode: the first visible ancestor before the "⋯" button. */
  get firstAncestor(): BreadcrumbItem | null {
    return this.items.length > 0 ? this.items[0] : null;
  }

  /** For overflow mode: nodes hidden inside the popover. */
  get hiddenAncestors(): BreadcrumbItem[] {
    return this.isOverflow ? this.items.slice(1, -1) : [];
  }

  onItemClick(item: BreadcrumbItem, index: number): void {
    if (this.type === 'breadcrumb') {
      this.itemClick.emit({ item, index });
    }
  }

  toggleOverflow(): void {
    this.overflowOpen = !this.overflowOpen;
  }
}

