import { Component, Input, ChangeDetectionStrategy } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Avatar } from 'primeng/avatar';

export type AvatarVariant = 'text' | 'image' | 'dummy';
export type AvatarSize = 'sm' | 'lg';

@Component({
  selector: 'ds-avatar',
  standalone: true,
  imports: [CommonModule, Avatar],
  templateUrl: './avatar.component.html',
  styleUrl: './avatar.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class AvatarComponent {
  /** Display variant: `text` shows initials, `image` shows a photo, `dummy` shows a placeholder icon. */
  @Input() variant: AvatarVariant = 'text';

  /** Size: `sm` = 32 px, `lg` = 72 px. */
  @Input() size: AvatarSize = 'sm';

  /** Initials to display when variant is `text` (e.g. "MN"). Max 2 chars. */
  @Input() initials = 'MN';

  /** Image URL to display when variant is `image`. */
  @Input() imageUrl = '';

  /** Alt text for the image. */
  @Input() imageAlt = '';

  get isText(): boolean { return this.variant === 'text'; }
  get isImage(): boolean { return this.variant === 'image'; }
  get isDummy(): boolean { return this.variant === 'dummy'; }
  get isLarge(): boolean { return this.size === 'lg'; }

  get hostClasses(): Record<string, boolean> {
    return {
      'ds-avatar': true,
      'ds-avatar--sm': this.size === 'sm',
      'ds-avatar--lg': this.size === 'lg',
      'ds-avatar--text': this.isText,
      'ds-avatar--image': this.isImage,
      'ds-avatar--dummy': this.isDummy,
    };
  }
}

import {
  Component,
  Input,
  Output,
  EventEmitter,
  ChangeDetectionStrategy,
} from '@angular/core';
import { CommonModule } from '@angular/common';

export type BreadcrumbType = 'breadcrumb' | 'navigation';
export type BreadcrumbLevel = 1 | 2 | 3 | 4;

/** A single item in the breadcrumb/navigation trail. */
export interface BreadcrumbItem {
  /** Displayed label for this node. */
  label: string;
  /** Optional route or URL (used for `href` on breadcrumb links). */
  href?: string;
}

/**
 * Breadcrumb & Navigation component.
 *
 * - **breadcrumb**: all ancestor nodes are clickable links with an underline;
 *   used when users can jump back to any previous screen.
 * - **navigation**: plain text trail with no links/underline;
 *   used for orientation-only context where back-navigation isn't supported.
 *
 * When there are more than 3 ancestors the component collapses them behind a
 * "⋯" overflow button that expands to reveal the hidden nodes.
 */
@Component({
  selector: 'ds-breadcrumb',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './breadcrumb.component.html',
  styleUrl: './breadcrumb.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class BreadcrumbComponent {
  /**
   * Ordered list of nodes from root → current page.
   * The **last** item is always treated as the active (non-clickable) page.
   */
  @Input() items: BreadcrumbItem[] = [];

  /**
   * `breadcrumb` — ancestor nodes are clickable links (underlined).
   * `navigation` — all nodes are plain text; no interaction.
   */
  @Input() type: BreadcrumbType = 'breadcrumb';

  /** Emits the clicked item index when a breadcrumb ancestor is clicked. */
  @Output() itemClick = new EventEmitter<{ item: BreadcrumbItem; index: number }>();

  /** Controls whether the overflow popover is open. */
  overflowOpen = false;

  /** Chevron SVG path — shared across all separators. */
  readonly CHEVRON = `M5.5 4l3.5 4-3.5 4`;

  /** Ellipsis icon path — shown when nodes are collapsed. */
  readonly ELLIPSIS = `M4 8a1 1 0 1 1 2 0A1 1 0 0 1 4 8zm4 0a1 1 0 1 1 2 0A1 1 0 0 1 8 8zm4 0a1 1 0 1 1 2 0A1 1 0 0 1 12 8`;

  /** Returns true when there are more than 3 ancestor nodes (Level 4+). */
  get isOverflow(): boolean {
    return this.items.length > 3;
  }

  /** Ancestor nodes — everything except the last (current) item. */
  get ancestors(): BreadcrumbItem[] {
    return this.items.slice(0, -1);
  }

  /** The current / active page item. */
  get current(): BreadcrumbItem | null {
    return this.items.length > 0 ? this.items[this.items.length - 1] : null;
  }

  /** For overflow mode: the first visible ancestor before the "⋯" button. */
  get firstAncestor(): BreadcrumbItem | null {
    return this.items.length > 0 ? this.items[0] : null;
  }

  /** For overflow mode: nodes hidden inside the popover. */
  get hiddenAncestors(): BreadcrumbItem[] {
    return this.isOverflow ? this.items.slice(1, -1) : [];
  }

  onItemClick(item: BreadcrumbItem, index: number): void {
    if (this.type === 'breadcrumb') {
      this.itemClick.emit({ item, index });
    }
  }

  toggleOverflow(): void {
    this.overflowOpen = !this.overflowOpen;
  }
}

import {
  Component,
  ContentChild,
  Input,
  Output,
  EventEmitter,
  ChangeDetectionStrategy,
  inject,
  TemplateRef,
} from '@angular/core';
import { CommonModule, NgTemplateOutlet } from '@angular/common';
import { DomSanitizer, SafeHtml } from '@angular/platform-browser';
import { ButtonModule } from 'primeng/button';

export type ButtonVariant = 'filled' | 'outlined' | 'ghost';
export type ButtonColor =
  | 'user'
  | 'admin'
  | 'secondary'
  | 'success'
  | 'error'
  | 'sunoh';
export type ButtonSize = 'sm' | 'md' | 'lg';
export type IconPosition = 'left' | 'right' | 'only';

@Component({
  selector: 'ds-button',
  standalone: true,
  imports: [CommonModule, ButtonModule, NgTemplateOutlet],
  templateUrl: './button.component.html',
  styleUrl: './button.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class ButtonComponent {
  @Input() label = 'Label';
  @Input() variant: ButtonVariant = 'filled';
  @Input() color: ButtonColor = 'user';
  @Input() size: ButtonSize = 'md';
  /** Inline SVG markup for the icon */
  @Input() set icon(svg: string | undefined) {
    this.safeIcon = svg ? this.sanitizer.bypassSecurityTrustHtml(svg) : undefined;
  }

  safeIcon?: SafeHtml;
  private sanitizer = inject(DomSanitizer);
  @Input() iconPosition: IconPosition = 'left';
  @Input() disabled = false;
  @Output() buttonClick = new EventEmitter<MouseEvent>();

  /** Custom icon/image template — use <ng-template #dsIcon> inside <ds-button> */
  @ContentChild('dsIcon') customIconTemplate?: TemplateRef<unknown>;

  get isIconOnly(): boolean {
    return this.iconPosition === 'only';
  }

  get hasIcon(): boolean {
    return !!(this.safeIcon || this.customIconTemplate);
  }

  /** Structural classes forwarded to the inner <button> via styleClass. */
  get styleClass(): string {
    const variantClass =
      this.variant === 'outlined' ? 'p-button-outlined'
      : this.variant === 'ghost' ? 'p-button-text'
      : '';

    const sizeClass =
      this.size === 'sm' ? 'p-button-sm'
      : this.size === 'lg' ? 'p-button-lg'
      : '';

    return [
      variantClass,
      `p-button-${this.color}`,
      sizeClass,
      this.isIconOnly ? 'p-button-icon-only' : '',
      this.disabled ? 'p-disabled' : '',
    ]
      .filter(Boolean)
      .join(' ');
  }

  /** Color theme class applied to the <p-button> host via [ngClass]. */
  get themeClass(): Record<string, boolean> {
    return { [`p-button-${this.color}`]: true };
  }

  onClick(event: MouseEvent): void {
    if (!this.disabled) {
      this.buttonClick.emit(event);
    }
  }
}

import { Component, Input, Output, EventEmitter, ChangeDetectionStrategy } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Checkbox } from 'primeng/checkbox';

@Component({
  selector: 'ds-checkbox',
  standalone: true,
  imports: [CommonModule, FormsModule, Checkbox],
  templateUrl: './checkbox.component.html',
  styleUrl: './checkbox.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class CheckboxComponent {
  /** Whether the checkbox is checked. */
  @Input() checked = false;

  /** Shows a dash instead of a checkmark — used when a group is partially selected. */
  @Input() indeterminate = false;

  /** Prevents user interaction and applies muted styles. */
  @Input() disabled = false;

  /** Label text displayed next to the checkbox. Set to empty string to hide the label. */
  @Input() label = 'Label';

  /** Emits the new checked state on every change. */
  @Output() checkedChange = new EventEmitter<boolean>();

  get hasLabel(): boolean {
    return this.label !== '';
  }

  handleChange(event: { checked?: boolean }): void {
    this.checked = !!event.checked;
    this.checkedChange.emit(this.checked);
  }
}

import {
  Component,
  Input,
  Output,
  EventEmitter,
  ChangeDetectionStrategy,
} from '@angular/core';
import { CommonModule } from '@angular/common';

/**
 * Chip / tag state — controls background colour and border colour.
 *
 * | State       | Background | Border    |
 * |-------------|-----------|-----------|
 * | `default`   | `#fbfbfb` | `#bcbcbc` |
 * | `active`    | `#f1fef8` | `#018145` |
 * | `error`     | `#ffefef` | `#d82727` |
 * | `warning`   | `#fff9eb` | `#fbce2a` |
 * | `in-process`| `#f1fbff` | `#0378a7` |
 * | `ai`        | `#f7f2ff` | `#7d58da` |
 */
export type ChipState =
  | 'default'
  | 'active'
  | 'error'
  | 'warning'
  | 'in-process'
  | 'ai';

/**
 * Chip / tag component — pill-shaped label used for status, categories, or
 * filtering.
 *
 * **Anatomy (all optional):**
 * `[badge] [icon] label [close ×]`
 *
 * - **Badge** — 16 × 16 px filled circle with a single letter (e.g. provider
 *   initial "P").
 * - **Icon** — 16 × 16 px SVG icon; supply a custom `iconPath` or use the
 *   built-in defaults (tag icon for standard states, sparkles for `ai`).
 * - **Label** — primary text, 12 px regular.
 * - **Close** — 16 × 16 px × button that emits `closed`.
 */
@Component({
  selector: 'ds-chip',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './chip.component.html',
  styleUrl: './chip.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class ChipComponent {
  /** Colour state applied to the chip border and background. */
  @Input() state: ChipState = 'default';

  /** Text label displayed in the chip. */
  @Input() label = 'Label';

  /** Show the left badge circle. */
  @Input() showBadge = true;

  /** Letter rendered inside the badge circle. */
  @Input() badgeLetter = 'P';

  /**
   * Background colour of the badge circle.
   * Defaults to the user/base blue (`#0378a7`).
   */
  @Input() badgeColor = '#0378a7';

  /** Show the icon slot between the badge and label. */
  @Input() showIcon = true;

  /**
   * Custom SVG `<path d="…">` data for the icon.
   * When omitted, a built-in default is used based on the chip `state`.
   * Use `viewBox="0 0 24 24"` paths — the icon is rendered at 16 × 16 px.
   */
  @Input() iconPath: string | null = null;

  /** Show the close × button at the right edge. */
  @Input() showClose = true;

  /** Emits when the close button is clicked. */
  @Output() closed = new EventEmitter<void>();

  /** Emits when the chip body is clicked. */
  @Output() chipClick = new EventEmitter<void>();

  // ─── Computed icon path ────────────────────────────────────────────────────

  get resolvedIconPath(): string {
    if (this.iconPath) return this.iconPath;
    if (this.state === 'ai') {
      // Auto-awesome / sparkles
      return 'M19 9l1.25-2.75L23 5l-2.75-1.25L19 1l-1.25 2.75L15 5l2.75 1.25L19 9zm-7.5.5L9 4 6.5 9.5 1 12l5.5 2.5L9 20l2.5-5.5L17 12l-5.5-2.5z';
    }
    // Label / tag icon
    return 'M17.63 5.84C17.27 5.33 16.67 5 16 5L5 5.01C3.9 5.01 3 5.9 3 7v10c0 1.1.9 1.99 2 1.99L16 19c.67 0 1.27-.33 1.63-.84L22 12l-4.37-6.16z';
  }

  get hostClasses(): Record<string, boolean> {
    return {
      'ds-chip': true,
      [`ds-chip--${this.state}`]: true,
    };
  }
}

import { Component, Input } from '@angular/core';

export interface ColorSwatch {
  name: string;
  hex: string;
  cssVar: string;
}

export interface ColorGroup {
  name: string;
  swatches: ColorSwatch[];
}

@Component({
  selector: 'ds-color-palette',
  standalone: true,
  imports: [],
  templateUrl: './color-palette.component.html',
  styleUrl: './color-palette.component.scss',
})
export class ColorPaletteComponent {
  @Input() groups: ColorGroup[] = [];

  /** Returns true if the color is light enough to need a border for contrast. */
  isLight(hex: string): boolean {
    const r = parseInt(hex.slice(0, 2), 16);
    const g = parseInt(hex.slice(2, 4), 16);
    const b = parseInt(hex.slice(4, 6), 16);
    return (r * 299 + g * 587 + b * 114) / 1000 > 160;
  }
}

import {
  Component,
  Input,
  Output,
  EventEmitter,
  ChangeDetectionStrategy,
} from '@angular/core';
import { CommonModule } from '@angular/common';

export type DisclaimerVariant = 'disclaimer' | 'ai-disclaimer';
export type DisclaimerLabelPosition = 'left' | 'top';

/**
 * Disclaimer banner component.
 *
 * Yellow warning strip — background `#fff9eb`, border `#fbce2a`.
 *
 * **Three layouts:**
 * - `disclaimer` + `labelPosition: 'left'` — "Disclaimer:" label inline with body text and close button.
 * - `disclaimer` + `labelPosition: 'top'` — "Disclaimer:" label on its own row, italic body text below and close button.
 * - `ai-disclaimer` — AI-specific text block + "Acknowledge for AI Assistant" secondary button.
 *
 * Typography:
 * - "Disclaimer:" label: **bold + italic**.
 * - Body text (`text`): italic for `disclaimer` · regular for `ai-disclaimer`.
 */
@Component({
  selector: 'ds-disclaimer',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './disclaimer.component.html',
  styleUrl: './disclaimer.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class DisclaimerComponent {
  /** Layout variant. */
  @Input() variant: DisclaimerVariant = 'disclaimer';

  /**
   * Position of the "Disclaimer:" label — `'left'` (inline) or `'top'` (own row).
   * Only relevant when `variant === 'disclaimer'`.
   */
  @Input() labelPosition: DisclaimerLabelPosition = 'left';

  /** Primary body text. */
  @Input() text = 'This content is for informational purposes only.';

  /** Optional second line of body text (shown below the first line). */
  @Input() line2 = '';

  /** Main text for the AI disclaimer (supports longer paragraphs). */
  @Input() aiText =
    'This feature uses artificial intelligence. AI-generated results may contain errors or inaccuracies.';

  /** Additional bolded note appended after the AI body text. */
  @Input() aiNote = 'Always verify AI-generated content with a qualified professional.';

  /** Label on the acknowledge button (AI variant). */
  @Input() acknowledgeLabel = 'Acknowledge for AI Assistant';

  /** Emits when the close button is clicked. */
  @Output() closed = new EventEmitter<void>();

  /** Emits when the acknowledge button is clicked (AI variant). */
  @Output() acknowledge = new EventEmitter<void>();
}

import {
  Component,
  Input,
  Output,
  EventEmitter,
  ChangeDetectionStrategy,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { TabItem, TabTheme, TAB_THEME_COLORS } from './tabs.types';

/**
 * Floating Tabs — minimal tab bar with a coloured underline indicator.
 *
 * No background box or border on the tabs themselves — they "float" above
 * a bottom border. The selected tab shows a theme-coloured 1 px underline
 * and SemiBold text; unselected tabs use Regular weight.
 *
 * The entire row sits on a full-width `#e1e1e1` bottom border.
 *
 * Themes: `user` (blue), `admin` (orange), `green`, `sunoh` (pink).
 */
@Component({
  selector: 'ds-floating-tabs',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './floating-tabs.component.html',
  styleUrl: './floating-tabs.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class FloatingTabsComponent {
  /** Tab items to render. */
  @Input() tabs: TabItem[] = [
    { key: 'tab1', label: 'Tab 1' },
    { key: 'tab2', label: 'Tab 2' },
    { key: 'tab3', label: 'Tab 3' },
  ];

  /** Key of the currently selected tab. */
  @Input() activeTab: string = 'tab1';

  /** Colour theme for the active underline. */
  @Input() theme: TabTheme = 'user';

  /** Emits the clicked tab's key. */
  @Output() tabChange = new EventEmitter<string>();

  get colors() {
    return TAB_THEME_COLORS[this.theme];
  }

  select(key: string): void {
    if (this.activeTab !== key) {
      this.tabChange.emit(key);
    }
  }
}

import {
  Component,
  Input,
