import {
  Component,
  Input,
  Output,
  EventEmitter,
  ChangeDetectionStrategy,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { TabItem, TabTheme, TAB_THEME_COLORS } from './tabs.types';

/**
 * Standard Tabs — classic bordered tab bar with a bottom underline.
 *
 * - **Selected tab**: white bg, 3-sided border (top/left/right) in theme
 *   colour, SemiBold label, rounded-top corners (4 px), flush with content.
 * - **Unselected tab**: light-tinted bg, lighter 3-sided border, Regular
 *   label, theme-coloured underline at bottom.
 * - A full-width theme-coloured rule runs beneath the entire tab bar.
 *
 * Themes: `user` (blue), `admin` (orange), `green`, `sunoh` (pink).
 */
@Component({
  selector: 'ds-standard-tabs',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './standard-tabs.component.html',
  styleUrl: './standard-tabs.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class StandardTabsComponent {
  /** Tab items to render. */
  @Input() tabs: TabItem[] = [
    { key: 'tab1', label: 'Tab 1' },
    { key: 'tab2', label: 'Tab 2' },
    { key: 'tab3', label: 'Tab 3' },
  ];

  /** Key of the currently selected tab. */
  @Input() activeTab: string = 'tab1';

  /** Colour theme for borders and underlines. */
  @Input() theme: TabTheme = 'user';

  /** Emits the clicked tab's key. */
  @Output() tabChange = new EventEmitter<string>();

  get colors() {
    return TAB_THEME_COLORS[this.theme];
  }

  select(key: string): void {
    if (this.activeTab !== key) {
      this.tabChange.emit(key);
    }
  }
}

import {
  Component,
  Input,
  Output,
  EventEmitter,
  ChangeDetectionStrategy,
  OnChanges,
  SimpleChanges,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';

// ─── Public types ─────────────────────────────────────────────────────────────

/** Data types supported by table columns. */
export type TableColumnType =
  | 'text'
  | 'date'
  | 'numeric'
  | 'dropdown'
  | 'button'
  | 'chip'
  | 'actions';

/** Sort direction. */
export type SortDirection = 'asc' | 'desc' | null;

/** Column definition. */
export interface TableColumn {
  /** Unique key matching a property in the row data object. */
  key: string;
  /** Display header label. */
  label: string;
  /** Render type for cell content. */
  type: TableColumnType;
  /** Whether this column is user-sortable. */
  sortable?: boolean;
  /** Optional fixed pixel width. */
  width?: number;
}

/** Per-row action emitted by the table. */
export interface TableRowAction {
  action: 'add' | 'edit' | 'delete';
  rowIndex: number;
  row: Record<string, unknown>;
}

/** Sort change event. */
export interface TableSortEvent {
  columnKey: string;
  direction: SortDirection;
}

/** Pagination state emitted when the page or page size changes. */
export interface TablePageEvent {
  page: number;
  pageSize: number;
}

/**
 * Table — configurable 1600 px data grid.
 *
 * Features:
 * - Toolbar with left and right action slots (projected via ng-content)
 * - Optional checkbox column (row selection)
 * - Optional expand column (expand-row toggle)
 * - Optional lock column (row lock indicator)
 * - Sortable column headers with up/down indicators and 3-dot overflow menu
 * - Row action column: + Add, ✏ Edit, 🗑 Delete
 * - Pagination footer: rows-per-page selector + first/prev/next/last navigation
 * - Chip and date/numeric rendering helpers
 */
@Component({
  selector: 'ds-table',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './table.component.html',
  styleUrl: './table.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class TableComponent implements OnChanges {
  // ─── Column config ────────────────────────────────────────────────────────

  /** Column definitions (ordered). */
  @Input() columns: TableColumn[] = [];

  // ─── Fixed utility columns ────────────────────────────────────────────────

  /** Show checkbox column for row selection. */
  @Input() showCheckbox = true;

  /** Show expand column (row drill-down toggle). */
  @Input() showExpand = true;

  /** Show lock column (lock indicator per row). */
  @Input() showLock = false;

  /** Show per-row action column (add / edit / delete). */
  @Input() showActions = true;

  // ─── Data ─────────────────────────────────────────────────────────────────

  /** Row data objects.  Keys must match `TableColumn.key` values. */
  @Input() rows: Record<string, unknown>[] = [];

  // ─── Selection state ──────────────────────────────────────────────────────

  /** Keys of selected rows (uses row index as key). */
  @Input() selectedRows: Set<number> = new Set();

  // ─── Sort state ───────────────────────────────────────────────────────────

  /** Currently sorted column key. */
  @Input() sortKey = '';

  /** Current sort direction. */
  @Input() sortDirection: SortDirection = null;

  // ─── Pagination ───────────────────────────────────────────────────────────

  /** Current page (1-based). */
  @Input() page = 1;

  /** Number of rows per page. */
  @Input() pageSize = 10;

  /** Total number of rows across all pages (for server-side pagination). */
  @Input() totalRows = 0;

  /** Options shown in the rows-per-page selector. */
  @Input() pageSizeOptions: number[] = [10, 25, 50, 100];

  // ─── Outputs ──────────────────────────────────────────────────────────────

  /** Emits when a column header sort is clicked. */
  @Output() sortChange = new EventEmitter<TableSortEvent>();

  /** Emits when page or page size changes. */
  @Output() pageChange = new EventEmitter<TablePageEvent>();

  /** Emits for row-level actions (add / edit / delete). */
  @Output() rowAction = new EventEmitter<TableRowAction>();

  /** Emits the updated selection Set when a checkbox is toggled. */
  @Output() selectionChange = new EventEmitter<Set<number>>();

  /** Emits the row index that was expanded/collapsed. */
  @Output() expandRow = new EventEmitter<number>();

  // ─── Internal state ───────────────────────────────────────────────────────

  expandedRows = new Set<number>();
  allSelected  = false;

  // ─── Derived ──────────────────────────────────────────────────────────────

  get totalPages(): number {
    const total = this.totalRows || this.rows.length;
    return Math.max(1, Math.ceil(total / this.pageSize));
  }

  get pageRows(): Record<string, unknown>[] {
    if (this.totalRows > 0) {
      // Server-side: rows are already the current page
      return this.rows;
    }
    const start = (this.page - 1) * this.pageSize;
    return this.rows.slice(start, start + this.pageSize);
  }

  get startRow(): number {
    return (this.page - 1) * this.pageSize + 1;
  }

  get endRow(): number {
    const total = this.totalRows || this.rows.length;
    return Math.min(this.page * this.pageSize, total);
  }

  get displayTotal(): number {
    return this.totalRows || this.rows.length;
  }

  ngOnChanges(changes: SimpleChanges): void {
    if (changes['rows']) {
      this.allSelected = false;
      this.expandedRows.clear();
    }
  }

  // ─── Selection ────────────────────────────────────────────────────────────

  toggleAll(checked: boolean): void {
    this.allSelected = checked;
    const next = new Set<number>();
    if (checked) {
      this.pageRows.forEach((_, i) => next.add((this.page - 1) * this.pageSize + i));
    }
    this.selectedRows = next;
    this.selectionChange.emit(this.selectedRows);
  }

  toggleRow(globalIndex: number): void {
    const next = new Set(this.selectedRows);
    next.has(globalIndex) ? next.delete(globalIndex) : next.add(globalIndex);
    this.selectedRows = next;
    this.allSelected  = this.pageRows.every((_, i) =>
      next.has((this.page - 1) * this.pageSize + i));
    this.selectionChange.emit(this.selectedRows);
  }

  // ─── Expand ───────────────────────────────────────────────────────────────

  toggleExpand(index: number): void {
    this.expandedRows.has(index) ? this.expandedRows.delete(index) : this.expandedRows.add(index);
    this.expandRow.emit(index);
  }

  // ─── Sort ─────────────────────────────────────────────────────────────────

  onSort(col: TableColumn): void {
    if (!col.sortable) return;
    let direction: SortDirection;
    if (this.sortKey !== col.key) {
      direction = 'asc';
    } else if (this.sortDirection === 'asc') {
      direction = 'desc';
    } else {
      direction = null;
    }
    this.sortKey       = direction ? col.key : '';
    this.sortDirection = direction;
    this.sortChange.emit({ columnKey: col.key, direction });
  }

  sortIcon(col: TableColumn): 'asc' | 'desc' | 'none' {
    if (this.sortKey !== col.key || !this.sortDirection) return 'none';
    return this.sortDirection;
  }

  // ─── Pagination ───────────────────────────────────────────────────────────

  goToPage(p: number): void {
    if (p < 1 || p > this.totalPages) return;
    this.page = p;
    this.pageChange.emit({ page: this.page, pageSize: this.pageSize });
  }

  onPageSizeChange(size: number): void {
    this.pageSize = Number(size);
    this.page     = 1;
    this.pageChange.emit({ page: this.page, pageSize: this.pageSize });
  }

  pageNumbers(): number[] {
    const range: number[] = [];
    const total = this.totalPages;
    const cur   = this.page;
    const delta = 2;
    for (let i = Math.max(1, cur - delta); i <= Math.min(total, cur + delta); i++) {
      range.push(i);
    }
    return range;
  }

  // ─── Cell helpers ─────────────────────────────────────────────────────────

  cellValue(row: Record<string, unknown>, key: string): string {
    const v = row[key];
    return v === null || v === undefined ? '' : String(v);
  }

  isRowSelected(globalIndex: number): boolean {
    return this.selectedRows.has(globalIndex);
  }

  globalIndex(pageRowIndex: number): number {
    return (this.page - 1) * this.pageSize + pageRowIndex;
  }
}

import {
  Component,
  Input,
  Output,
  EventEmitter,
  ChangeDetectionStrategy,
} from '@angular/core';
import { CommonModule } from '@angular/common';

export type ToastType = 'confirmation' | 'communication';

/**
 * Toast notification component.
 *
 * Fixed height: **56 px** · Min width: 520 px · Max width: 600 px.
 *
 * Two types:
 * - `confirmation` — green background, checkmark icon, optional **Undo** button.
 * - `communication` — dark gray background, info icon.
 *
 * White text throughout.
 */
@Component({
  selector: 'ds-toast',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './toast.component.html',
  styleUrl: './toast.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class ToastComponent {
  /** Visual type — changes background colour and icon. */
  @Input() type: ToastType = 'confirmation';

  /** Window / screen name shown in bold. */
  @Input() windowName = 'Window Name';

  /** Brief description shown after the window name. */
  @Input() description = 'Action completed successfully.';

  /** Optional second line of body text. */
  @Input() line2 = '';

  /**
   * When true, renders an **Undo** button next to the close icon.
   * Only visible on `confirmation` type.
   */
  @Input() showUndo = false;

  /** Label for the undo button (e.g. "Undo 5 Sec"). */
  @Input() undoLabel = 'Undo 5 Sec';

  /** Emits when the close button is clicked. */
  @Output() closed = new EventEmitter<void>();

  /** Emits when the undo button is clicked. */
  @Output() undoClick = new EventEmitter<void>();

  // ─── Icon paths ───────────────────────────────────────────────────────────

  get iconPath(): string {
    switch (this.type) {
      case 'confirmation':
        // Checkmark
        return 'M9 16.17L4.83 12l-1.42 1.41L9 19 21 7l-1.41-1.41z';
      case 'communication':
        // Info circle
        return 'M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-6h2v6zm0-8h-2V7h2v2z';
    }
  }
}

import {
  Component,
  Input,
  Output,
  EventEmitter,
  ChangeDetectionStrategy,
  inject,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { DomSanitizer, SafeHtml } from '@angular/platform-browser';

/** A single option within the toggle button group. */
export interface ToggleButtonItem {
  /** Unique value used to track selection state. */
  value: string;
  /** Label text rendered inside the button. Omit for icon-only buttons. */
  label?: string;
  /** Optional numeric badge (e.g. 99 → shows "Label (99)"). */
  count?: number;
  /** Inline SVG string for an icon. Shown for icon-only or icon+label buttons. */
  icon?: string;
  /** Disables this individual button. */
  disabled?: boolean;
}

export type ToggleColor =
  | 'user'
  | 'admin'
  | 'secondary'
  | 'success'
  | 'error'
  | 'sunoh';

export type ToggleSize = 'sm' | 'md' | 'lg';

/** Built-in checkmark SVG shown in the selected state (label buttons). */
const CHECK_SVG = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="13,3.5 6,12.5 3,8.5"/></svg>`;

@Component({
  selector: 'ds-toggle-button-group',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './toggle-button-group.component.html',
  styleUrl: './toggle-button-group.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class ToggleButtonGroupComponent {
  /** Array of button options to render. */
  @Input() options: ToggleButtonItem[] = [];

  /** Color theme applied to the selected button and group border. */
  @Input() color: ToggleColor = 'user';

  /** Height / padding scale: `sm` = 24 px, `md` = 32 px, `lg` = 40 px. */
  @Input() size: ToggleSize = 'md';

  /**
   * When `true`, multiple buttons can be selected simultaneously.
   * When `false` (default), behaves like a radio group — selecting one
   * deselects the others.
   */
  @Input() multiple = false;

  /** Disables all buttons in the group. */
  @Input() disabled = false;

  /**
   * Currently selected value(s).
   * Pass a `string` when `multiple = false`, or `string[]` when `multiple = true`.
   */
  @Input() value: string | string[] = '';

  /** Emits the new selected value (or array of values) after each toggle. */
  @Output() valueChange = new EventEmitter<string | string[]>();

  private sanitizer = inject(DomSanitizer);

  /** Pre-sanitised checkmark icon rendered in selected label-buttons. */
  readonly checkIcon: SafeHtml = this.sanitizer.bypassSecurityTrustHtml(CHECK_SVG);

  /** Returns a sanitised SafeHtml for user-supplied icon SVGs. */
  safeIcon(svg: string): SafeHtml {
    return this.sanitizer.bypassSecurityTrustHtml(svg);
  }

  /** Returns true when the given option value is currently selected. */
  isSelected(value: string): boolean {
    if (this.multiple) {
      return Array.isArray(this.value) && (this.value as string[]).includes(value);
    }
    return this.value === value;
  }

  /** Returns true when the option has no label (icon-only button). */
  isIconOnly(item: ToggleButtonItem): boolean {
    return !item.label && !!item.icon;
  }

  /** Called when a button is clicked. Updates the internal selection model. */
  onToggle(item: ToggleButtonItem): void {
    if (this.disabled || item.disabled) return;

    if (this.multiple) {
      const current = Array.isArray(this.value) ? [...(this.value as string[])] : [];
      const idx = current.indexOf(item.value);
      if (idx >= 0) current.splice(idx, 1);
      else current.push(item.value);
      this.value = current;
      this.valueChange.emit([...current]);
    } else {
      this.value = item.value;
      this.valueChange.emit(item.value);
    }
  }

  get groupClasses(): Record<string, boolean> {
    return {
      [`ds-tgl--${this.color}`]: true,
      [`ds-tgl--${this.size}`]: true,
      'ds-tgl--disabled': this.disabled,
    };
  }

  itemClasses(item: ToggleButtonItem): Record<string, boolean> {
    return {
      'ds-tgl__btn--selected': this.isSelected(item.value),
      'ds-tgl__btn--disabled': !!(item.disabled || this.disabled),
      'ds-tgl__btn--icon-only': this.isIconOnly(item),
    };
  }
}

import { Component, Input, Output, EventEmitter, ChangeDetectionStrategy } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ToggleSwitch } from 'primeng/toggleswitch';

export type ToggleTheme = 'user' | 'admin' | 'green' | 'sunoh';

@Component({
  selector: 'ds-toggle',
  standalone: true,
  imports: [CommonModule, FormsModule, ToggleSwitch],
  templateUrl: './toggle.component.html',
  styleUrl: './toggle.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class ToggleComponent {
  /** Whether the toggle is on. */
  @Input() on = false;

  /** Colour theme. */
  @Input() theme: ToggleTheme = 'user';

  /** Prevents user interaction. */
  @Input() disabled = false;

  /** Emits the new on/off state. */
  @Output() onToggle = new EventEmitter<boolean>();

  handleChange(event: { checked: boolean }): void {
    this.on = event.checked;
    this.onToggle.emit(event.checked);
  }

  get hostClasses(): Record<string, boolean> {
    return {
      'ds-toggle': true,
      [`ds-toggle--${this.theme}`]: true,
      'ds-toggle--disabled': this.disabled,
    };
  }
}

