  };

  get colors() {
    return this.themes[this.theme];
  }

  isActive(key: string): boolean {
    return this.activeStep === key;
  }

  select(key: string): void {
    if (this.activeStep !== key) {
      this.stepChange.emit(key);
    }
  }
}

